def first_missing_positive(nums):
    n = len(nums)
    i = 0
    while i < n:
        v = nums[i]
        pos = v - 1
        if 1 <= v <= n and nums[pos] != v:
            nums[i], nums[pos] = nums[pos], nums[i]
        else:
            i += 1
    for i in range(n):
        if nums[i] != i + 1:
            return i + 1
    return n + 1

